#!/usr/bin/env node
/**
 * sync-lambda-graphql.js
 *
 * Reads the Amplify-autogenerated GraphQL files (ESM) and writes a CJS
 * re-export of the operations needed by botchattriggerjs into the Lambda's
 * src/ directory.
 *
 * Run this after any `amplify codegen` or schema change:
 *   node scripts/sync-lambda-graphql.js
 *
 * The output file is committed to source control so it is included in the
 * Lambda deployment package when Amplify packages and zips the function.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');

// Source: autogenerated ESM files
const mutationsPath = path.join(ROOT, 'src', 'graphql', 'mutations.js');
const queriesPath   = path.join(ROOT, 'src', 'graphql', 'queries.js');

// Destination: Lambda source directory
const outPath = path.join(ROOT, 'amplify', 'backend', 'function', 'botchattriggerjs', 'src', 'graphql.js');

/**
 * Extracts the template-literal value of a named `export const` from an
 * autogenerated Amplify GraphQL file.
 *
 * The files use the pattern:
 *   export const <name> = \/* GraphQL *\/ `...`;
 */
function extractExport(source, name) {
  // Match: export const <name> = /* GraphQL */ `...`;
  // The template literal may span multiple lines.
  const re = new RegExp(
    `export const ${name}\\s*=\\s*\\/\\*\\s*GraphQL\\s*\\*\\/\\s*\`([\\s\\S]*?)\`\\s*;`,
  );
  const match = source.match(re);
  if (!match) throw new Error(`Could not find export "${name}" in source`);
  return match[1]; // the raw template literal content (without backticks)
}

const mutations = fs.readFileSync(mutationsPath, 'utf8');
const queries   = fs.readFileSync(queriesPath,   'utf8');

const createChat          = extractExport(mutations, 'createChat');
const updatePersonalities = extractExport(mutations, 'updatePersonalities');
const listPersonalities   = extractExport(queries,   'listPersonalities');
const listChats           = extractExport(queries,   'listChats');

const output = `// AUTO-GENERATED by scripts/sync-lambda-graphql.js
// Do not edit by hand — run \`npm run sync-lambda-graphql\` after any schema change.
// Source: src/graphql/mutations.js and src/graphql/queries.js

const createChat = /* GraphQL */ \`${createChat}\`;

const updatePersonalities = /* GraphQL */ \`${updatePersonalities}\`;

const listPersonalities = /* GraphQL */ \`${listPersonalities}\`;

const listChats = /* GraphQL */ \`${listChats}\`;

module.exports = { createChat, updatePersonalities, listPersonalities, listChats };
`;

fs.writeFileSync(outPath, output, 'utf8');
console.log(`Written: ${path.relative(ROOT, outPath)}`);
